mapper.select:
SELECT
    NOW() AS reportDate,
    (SELECT COUNT(*)
     FROM pi_targets
     WHERE TARGET_USE = 'Y'

            AND GROUP_IDX IN (
                WITH RECURSIVE CTE AS (
                    SELECT IDX FROM pi_target_group WHERE IDX = #{groupId}
                    UNION ALL
                    SELECT tg.IDX FROM pi_target_group tg INNER JOIN CTE ON tg.UP_IDX = CTE.IDX
                )
                SELECT IDX FROM CTE
            )

    ) AS totalTargets,
    (SELECT COUNT(DISTINCT f2.TARGET_ID)
     FROM pi_find f2
     INNER JOIN pi_targets t2 ON f2.TARGET_ID = t2.TARGET_ID AND f2.AP_NO = t2.AP_NO
     WHERE t2.TARGET_USE = 'Y'

            AND t2.GROUP_IDX IN (
                WITH RECURSIVE CTE AS (
                    SELECT IDX FROM pi_target_group WHERE IDX = #{groupId}
                    UNION ALL
                    SELECT tg.IDX FROM pi_target_group tg INNER JOIN CTE ON tg.UP_IDX = CTE.IDX
                )
                SELECT IDX FROM CTE
            )


            AND f2.REGDATE >= #{startDate}


            AND f2.REGDATE <= #{endDate}

    ) AS scannedTargets,
    COUNT(DISTINCT f.HASH_ID) AS totalDetections,
    SUM(CASE WHEN dp.PROCESSING_FLAG IS NOT NULL THEN 1 ELSE 0 END) AS processedDetections,
    SUM(CASE WHEN dp.APPROVAL_STATUS = 'Y' THEN 1 ELSE 0 END) AS truePositives,
    SUM(CASE WHEN dp.APPROVAL_STATUS = 'N' THEN 1 ELSE 0 END) AS falsePositives,
    SUM(CASE WHEN dp.APPROVAL_STATUS = 'Y' AND dp.PROCESSING_FLAG IS NOT NULL THEN 1 ELSE 0 END) AS remediatedCount
FROM pi_find f
INNER JOIN pi_targets t ON f.TARGET_ID = t.TARGET_ID AND f.AP_NO = t.AP_NO
LEFT JOIN pi_data_processing dp ON f.TARGET_ID = dp.TARGET_ID AND f.HASH_ID = dp.HASH_ID
WHERE t.TARGET_USE = 'Y'

    AND t.GROUP_IDX IN (
        WITH RECURSIVE CTE AS (
            SELECT IDX FROM pi_target_group WHERE IDX = #{groupId}
            UNION ALL
            SELECT tg.IDX FROM pi_target_group tg INNER JOIN CTE ON tg.UP_IDX = CTE.IDX
        )
        SELECT IDX FROM CTE
    )


    AND f.REGDATE >= #{startDate}


    AND f.REGDATE <= #{endDate}

SELECT DATE_FORMAT(f.REGDATE, '%Y-%m') AS month, COUNT(*) AS totalDetections, SUM(CASE WHEN dp.PROCESSING_FLAG IS NOT NULL THEN 1 ELSE 0 END) AS processedCount, SUM(CASE WHEN dp.APPROVAL_STATUS = 'Y' THEN 1 ELSE 0 END) AS truePositiveCount, SUM(CASE WHEN dp.APPROVAL_STATUS = 'N' THEN 1 ELSE 0 END) AS falsePositiveCount, SUM(CASE WHEN dp.APPROVAL_STATUS = 'Y' AND dp.PROCESSING_FLAG IS NOT NULL THEN 1 ELSE 0 END) AS remediatedCount, COUNT(DISTINCT f.TARGET_ID) AS targetCount FROM pi_find f INNER JOIN pi_targets t ON f.TARGET_ID = t.TARGET_ID AND f.AP_NO = t.AP_NO LEFT JOIN pi_data_processing dp ON f.TARGET_ID = dp.TARGET_ID AND f.HASH_ID = dp.HASH_ID WHERE t.TARGET_USE = 'Y'
AND f.REGDATE >= #{startDate}
AND f.REGDATE <= #{endDate}
GROUP BY DATE_FORMAT(f.REGDATE, '%Y-%m') ORDER BY month ASC

SELECT t.TARGET_ID AS targetId, t.NAME AS targetName, IFNULL(a.AGENT_CONNECTED_IP, '') AS targetIp, COUNT(DISTINCT f.HASH_ID) AS detectionCount, SUM(CASE WHEN dp.PROCESSING_FLAG IS NOT NULL THEN 1 ELSE 0 END) AS processedCount, SUM(CASE WHEN dp.APPROVAL_STATUS = 'Y' THEN 1 ELSE 0 END) AS truePositiveCount, SUM(CASE WHEN dp.APPROVAL_STATUS = 'N' THEN 1 ELSE 0 END) AS falsePositiveCount, SUM(CASE WHEN dp.APPROVAL_STATUS = 'Y' AND dp.PROCESSING_FLAG IS NOT NULL THEN 1 ELSE 0 END) AS remediatedCount, MAX(f.REGDATE) AS lastScanDate FROM pi_targets t LEFT JOIN pi_find f ON t.TARGET_ID = f.TARGET_ID AND t.AP_NO = f.AP_NO
AND f.REGDATE >= #{startDate}
AND f.REGDATE <= #{endDate}
LEFT JOIN pi_data_processing dp ON f.TARGET_ID = dp.TARGET_ID AND f.HASH_ID = dp.HASH_ID LEFT JOIN pi_agents a ON t.NAME = a.AGENT_NAME AND t.AP_NO = a.AP_NO WHERE t.TARGET_USE = 'Y'
AND t.GROUP_IDX IN ( WITH RECURSIVE CTE AS ( SELECT IDX FROM pi_target_group WHERE IDX = #{groupId} UNION ALL SELECT tg.IDX FROM pi_target_group tg INNER JOIN CTE ON tg.UP_IDX = CTE.IDX ) SELECT IDX FROM CTE )
AND t.TARGET_ID = #{targetId}
GROUP BY t.TARGET_ID, t.AP_NO, t.NAME, a.AGENT_CONNECTED_IP ORDER BY detectionCount DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM (
    SELECT t.TARGET_ID
    FROM pi_targets t
    LEFT JOIN pi_find f ON t.TARGET_ID = f.TARGET_ID AND t.AP_NO = f.AP_NO

            AND f.REGDATE >= #{startDate}


            AND f.REGDATE <= #{endDate}

    WHERE t.TARGET_USE = 'Y'

        AND t.GROUP_IDX IN (
            WITH RECURSIVE CTE AS (
                SELECT IDX FROM pi_target_group WHERE IDX = #{groupId}
                UNION ALL
                SELECT tg.IDX FROM pi_target_group tg INNER JOIN CTE ON tg.UP_IDX = CTE.IDX
            )
            SELECT IDX FROM CTE
        )


        AND t.TARGET_ID = #{targetId}

    GROUP BY t.TARGET_ID, t.AP_NO
) AS cnt

SELECT t.NAME AS targetName, IFNULL(a.AGENT_CONNECTED_IP, '') AS targetIp, IFNULL(tg.NAME, '') AS groupName, t.GROUP_IDX AS groupId, f.PATH AS findPath, s.DATA_TYPE AS datatype, f.REGDATE AS findDate, CASE WHEN dp.PROCESSING_FLAG IS NOT NULL THEN 'Y' ELSE 'N' END AS processYn, CASE WHEN dp.APPROVAL_STATUS = 'Y' THEN 'Y' WHEN dp.APPROVAL_STATUS = 'N' THEN 'N' ELSE NULL END AS trueYn, CASE WHEN dp.APPROVAL_STATUS = 'Y' AND dp.PROCESSING_FLAG IS NOT NULL THEN 'Y' ELSE 'N' END AS remediateYn, dp.REGDATE AS processDate, dp.USER_NO AS processUser FROM pi_find f INNER JOIN pi_targets t ON f.TARGET_ID = t.TARGET_ID AND f.AP_NO = t.AP_NO LEFT JOIN pi_summary s ON f.TARGET_ID = s.TARGET_ID AND f.AP_NO = s.AP_NO AND f.HASH_ID = s.OBJECT_ID LEFT JOIN pi_data_processing dp ON f.TARGET_ID = dp.TARGET_ID AND f.HASH_ID = dp.HASH_ID LEFT JOIN pi_agents a ON t.NAME = a.AGENT_NAME AND t.AP_NO = a.AP_NO LEFT JOIN pi_target_group tg ON t.GROUP_IDX = tg.IDX WHERE t.TARGET_USE = 'Y'
AND dp.APPROVAL_STATUS = 'Y'
AND dp.APPROVAL_STATUS = 'N'
AND dp.PROCESSING_FLAG IS NULL
AND t.GROUP_IDX IN ( WITH RECURSIVE CTE AS ( SELECT IDX FROM pi_target_group WHERE IDX = #{groupId} UNION ALL SELECT tg2.IDX FROM pi_target_group tg2 INNER JOIN CTE ON tg2.UP_IDX = CTE.IDX ) SELECT IDX FROM CTE )
AND t.TARGET_ID = #{targetId}
AND f.REGDATE >= #{startDate}
AND f.REGDATE <= #{endDate}
ORDER BY t.NAME ASC, f.REGDATE DESC
